%[text] ME5405 Machine Vision - Image 2: Characters (charact1.txt)
%[text] This script performs Tasks 2.1-2.7 on Image 2.
%[text] The image shows characters 1,2,3 (top row) and A,B,C (bottom row) as bright objects on a black background.
close all; clear; clc;

addpath('src/lib');
data_dir    = './data/';
results_dir = './results/';
%[text] Task 2.1: Display the original image
% ----------------------------------------------------------
% 01 Display Original Image
% ----------------------------------------------------------

fprintf('=== Task 2.1: Display Original Image ===\n'); %[output:942e9bb4]

img = load_txt2img([data_dir 'charact1.txt']); %[output:79bdbdf6]

figure('Name','[Task 2] Original Image'); %[output:2e7f0166]
imshow(img, 'DisplayRange', [min(img(:)) max(img(:))], 'InitialMagnification', 'fit'); %[output:2e7f0166]
title('Image 2: Chromosomes (Original)'); axis ('on', 'image'); colorbar; %[output:2e7f0166]
saveas(gcf,[results_dir 'img2_01_original.png']); %[output:2e7f0166]

figure('Name','[Task 2] Intensity Histogram'); %[output:8d87dd32]
histogram(img, 'BinEdges', 0.5:1:32.5); %[output:8d87dd32]
xlabel('Intensity Level'); %[output:8d87dd32]
ylabel('Frequency'); %[output:8d87dd32]
title('Image 2: Intensity Histogram'); %[output:8d87dd32]
xlim([0 32]); %[output:8d87dd32]
saveas(gcf,[results_dir 'img2_02_histogram.png']); %[output:8d87dd32]
%[text] Task 2.2: Threshold into binary image
% ----------------------------------------------------------
% 02 Otsu Thresholding Binary Image
% ----------------------------------------------------------

fprintf('=== Task 2.2: Threshold Into Binary Image ===\n'); %[output:1e12f8ff]

[T, threshold] = otsu_threshold(img); %[output:7ea722ea]

figure('Name','[Task 2] Thresholded Binary Image'); %[output:6dfaa896]
imshow(T, 'InitialMagnification', 'fit') %[output:6dfaa896]
title(sprintf('Image 2: Otsu Threshold k* = %d', threshold-1)); axis ('on', 'image'); %[output:6dfaa896]
saveas(gcf,[results_dir 'img2_03_binarized.png']); %[output:6dfaa896] %[output:09783647]
%[text] Task 2.3: One-pixel thin image (skeletonization)
% ----------------------------------------------------------
% 03 Zhang-Suen Thinning Skeletonized Image
% ----------------------------------------------------------

fprintf('=== Task 2.3: One-Pixel Thin Image Skeletonization ===\n'); %[output:81565618]

thinned = zs_thinning(T, 1); %[output:428defaf]

figure('Name','[Task 2] One-Pixel Thin Image'); %[output:78c6d488]
imshow(thinned, 'InitialMagnification', 'fit'); %[output:78c6d488]
title('Image 2: One-pixel Thin Image'); axis ('on', 'image'); %[output:78c6d488]
saveas(gcf,[results_dir 'img2_04_skeletonized.png']); %[output:78c6d488]
%[text] Task 2.4: Determine boundary outlines
% ----------------------------------------------------------
% 04 Outline Detection Boundary Image
% ----------------------------------------------------------

fprintf('=== Task 2.4: Determine Image Boundary Outlines ===\n'); %[output:8c5d178d]

bound = boundary_detect(T, 1);

figure('Name','[Task 2] Outline Detection Image'); %[output:904d5c61]
imshow(bound, 'InitialMagnification', 'fit') %[output:904d5c61]
title('Image 2: Boundary Outline'); axis ('on', 'image'); %[output:904d5c61]
saveas(gcf,[results_dir 'img2_05_outline.png']); %[output:904d5c61]
%[text] Task 2.5: Label different objects
% ----------------------------------------------------------
% 05 Object Labeling Image Segmentation
% ----------------------------------------------------------

fprintf('=== Task 2.5: Segment Image and Label Objects ===\n'); %[output:612f7033]

[label_matrix, num_components] = ccl_segment(T, 1); %[output:424d93fe]

display_matrix = double(label_matrix);
display_matrix(label_matrix == 0) = NaN;

figure('Name','[Task 2] Segmented Image'); %[output:197c4762]
imagesc(display_matrix, 'AlphaData', ~isnan(display_matrix)); %[output:197c4762]
set(gca, 'Color', 'white'); colormap(jet); colorbar; %[output:197c4762]
title(sprintf('Image 2: Segmenting - %d regions found', num_components)); %[output:197c4762]
axis ('on', 'image'); %[output:197c4762]
saveas(gcf,[results_dir 'img2_06_segmenting.png']); %[output:197c4762]
%[text] Task 2.6: Arrange characters as AB123C
% ----------------------------------------------------------
% 06 Arrange Character Sequence
% ----------------------------------------------------------

fprintf('\n=== Task 2.6: Arrange as AB123C ===\n'); %[output:3c99db0f]

% "AB123C"  →  components 4, 5, 1, 2, 3, 6
arranged = arrange_chars(T, label_matrix, [4 5 1 2 3 6], 0); %[output:36134af7]

figure('Name','[Task 2] Sequence Characters - AB123C Sequence'); %[output:5a1ac247]
imshow(arranged, 'InitialMagnification', 'fit'); %[output:5a1ac247]
title('Image 2: Arranged Characters'); axis ('on', 'image'); %[output:5a1ac247]
saveas(gcf,[results_dir 'img2_07_arranged.png']); %[output:5a1ac247]
%[text] Task 2.7: Rotate by 30 degrees about center
% ----------------------------------------------------------
% 07 Image Rotation
% ----------------------------------------------------------

fprintf('\n=== Task 2.7: Rotate image by 30 degrees ===\n'); %[output:3da8cbcf]

% Rotate 30 degrees clockwise, white background
rotated = rotate_image(arranged, 30, 'cw', 1); %[output:3af78530]

figure('Name','[Task 2] Rotated Image'); %[output:06a28d67]
imshow(rotated, 'InitialMagnification', 'fit'); %[output:06a28d67]
title('Image 2: AB123C Rotated 30° Clockwise'); axis ('on', 'image'); %[output:06a28d67]
saveas(gcf,[results_dir 'img2_08_rotated.png']); %[output:06a28d67]

